function populateStateDropdown() {
  const sel = document.getElementById('addrState');
  if(!sel || sel.options.length > 1) return;
  Object.keys(INDIA_STATES_DISTRICTS).sort().forEach(state=>{
    const opt = document.createElement('option');
    opt.value = state;
    opt.textContent = state;
    sel.appendChild(opt);
  });
}
function onStateChange() {
  const state = document.getElementById('addrState').value;
  const distSel = document.getElementById('addrDistrict');
  distSel.innerHTML = '';
  if(!state) {
    distSel.disabled = true;
    distSel.innerHTML = '<option value="">Select State First</option>';
    return;
  }
  distSel.disabled = false;
  distSel.innerHTML = '<option value="">Select District</option>' +
    (INDIA_STATES_DISTRICTS[state]||[]).map(d=>`<option value="${d}">${d}</option>`).join('');
}
