function resizeImageFile(file, maxDim, quality) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        let { width, height } = img;
        if (width > height && width > maxDim) { height = Math.round(height * maxDim / width); width = maxDim; }
        else if (height >= width && height > maxDim) { width = Math.round(width * maxDim / height); height = maxDim; }
        const canvas = document.createElement('canvas');
        canvas.width = width; canvas.height = height;
        canvas.getContext('2d').drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', quality));
      };
      img.onerror = () => reject(new Error('Image load failed'));
      img.src = e.target.result;
    };
    reader.onerror = () => reject(new Error('File read failed'));
    reader.readAsDataURL(file);
  });
}
async function galleryHandleReplace(file) {
  if (!file) return;
  if (!homeGallery.length) homeGallery = DEFAULT_HOME_GALLERY.slice();
  try {
    showToast('⏳ Photo upload ho rahi hai...');
    let compressed = await resizeImageFile(file, 480, 0.65);
    if (compressed.length > 400000) {
      compressed = await resizeImageFile(file, 360, 0.55);
    }
    homeGallery[_galleryReplaceIdx] = compressed;
    renderHomeGallery(); 
    await saveHomeGalleryToFirebase(); 
    showToast('✓ Photo replace ho gayi aur save bhi ho gayi!');
  } catch (e) {
    console.error('Gallery replace failed:', e);
    showToast('⚠ Photo replace nahi ho payi: ' + (e && e.message || 'unknown error'));
  }
  document.getElementById('galleryReplaceInput').value = '';
}
async function galleryRemoveImage(i) {
  if (!confirm('Ye photo home page se remove karni hai?')) return;
  if (!homeGallery.length) homeGallery = DEFAULT_HOME_GALLERY.slice();
  homeGallery.splice(i, 1);
  renderHomeGallery();
  await saveHomeGalleryToFirebase();
  showToast('✓ Photo remove ho gayi!');
}
async function galleryAddImages(files) {
  if (!files || !files.length) return;
  if (!homeGallery.length) homeGallery = DEFAULT_HOME_GALLERY.slice();
  try {
    showToast('⏳ Photos upload ho rahi hain...');
    for (const file of Array.from(files)) {
      let compressed = await resizeImageFile(file, 480, 0.65);
      if (compressed.length > 400000) {
        compressed = await resizeImageFile(file, 360, 0.55);
      }
      homeGallery.push(compressed);
    }
    renderHomeGallery();
    await saveHomeGalleryToFirebase();
    showToast('✓ Photo(s) add ho gayi aur save bhi ho gayi!');
  } catch (e) {
    console.error('Gallery add failed:', e);
    showToast('⚠ Photo add karne mein error aayi: ' + (e && e.message || 'unknown error'));
  }
  document.getElementById('galleryAddInput').value = '';
}
async function saveHomeGalleryToFirebase() {
  try {
    const { db, ref, set } = window.fb;
    const totalSize = JSON.stringify(homeGallery).length;
    if (totalSize > 9000000) {
      showToast("⚠ Gallery ka total size bahut bada hai! Kuch photos remove karo.");
      return;
    }
    await set(ref(db, 'settings/homeGallery'), homeGallery);
  } catch (e) {
    console.error('saveHomeGalleryToFirebase error:', e);
    showFirebaseError('saving home gallery', e);
    throw e;
  }
}
