const CAT_LABELS = {tshirt:'T-Shirts', hoodie:'Hoodies', polo:'Polos', jacket:'Jackets', trouser:'Trousers', accessories:'Accessories'};
function catLabel(cat) { return CAT_LABELS[cat] || (cat ? cat.charAt(0).toUpperCase()+cat.slice(1) : ''); }
const CAT_SUBTITLE = {
  tshirt:'Relaxed Fit • Premium Cotton • Breathable',
  hoodie:'Oversized Fit • Heavy Fleece • Cozy Warmth',
  polo:'Classic Fit • Pique Cotton • Fade-Resistant',
  jacket:'Tailored Fit • Premium Shell • All-Weather',
  trouser:'Tapered Fit • Stretch Fabric • All-Day Comfort',
  accessories:'Premium Materials • Built to Last'
};
function pdSubtitle(p) { return CAT_SUBTITLE[p.cat] || 'Premium Quality • Everyday Comfort'; }
const CAT_FEATURES = {
  tshirt:['Premium combed cotton fabric','Relaxed, breathable fit','Reinforced stitching for durability','Pre-shrunk fabric','Bio-washed for extra softness'],
  hoodie:['Heavyweight fleece interior','Oversized streetwear fit','Ribbed cuffs and hem','Adjustable drawstring hood','Spacious kangaroo pocket'],
  polo:['Fade-resistant pique cotton','Classic tailored collar','Two-button placket','Breathable all-day comfort','Easy-iron fabric'],
  jacket:['Weather-resistant outer shell','Quilted inner lining','Smooth zip closure','Secure side pockets','Tailored silhouette'],
  trouser:['Stretch-woven fabric','Tapered, modern fit','Reinforced belt loops','Wrinkle-resistant finish','Functional pockets'],
  accessories:['Premium materials','Built for daily use','Compact and durable','Versatile styling','Thoughtful detailing']
};
function pdFeatures(cat) { return CAT_FEATURES[cat] || CAT_FEATURES.tshirt; }
const COLOR_HEX = {black:'#1a1a1a',white:'#f0f0f0',navy:'#1b2a4a',grey:'#888888',gray:'#888888',olive:'#5c5f3a',red:'#b33a3a',blue:'#2f5fa8',green:'#3f6b4a',beige:'#cdbfa3',brown:'#6b4a33',pink:'#d98aa6',yellow:'#d9c25a',orange:'#cc7a3a',maroon:'#6e2a2a',cream:'#e9e2cf',ivory:'#ece6d6'};
function colorToHex(name) { return COLOR_HEX[String(name||'').trim().toLowerCase()] || '#888'; }
function pdRatingFor(p) {
  let h = 0;
  const s = 'sh'+p.id+(p.name||'');
  for (let i=0;i<s.length;i++) h = (h*31 + s.charCodeAt(i)) >>> 0;
  const avg = +(4.3 + (h % 6)/10).toFixed(1);
  const count = 38 + (h % 180);
  return { avg, count };
}
function pdStarsHTML(avg) {
  const full = Math.round(avg);
  return '★'.repeat(full) + '☆'.repeat(5-full);
}
function pdReviewBars() {
  return [{star:5,pct:90},{star:4,pct:7},{star:3,pct:2},{star:2,pct:1},{star:1,pct:0}];
}
function pdDeliveryEstimate() {
  const now = new Date();
  const cutoff = new Date(now); cutoff.setHours(18,0,0,0);
  const pastCutoff = now >= cutoff;
  const diffMs = (pastCutoff ? (() => { const n=new Date(cutoff); n.setDate(n.getDate()+1); return n; })() : cutoff) - now;
  const hrs = Math.max(0, Math.floor(diffMs/3600000));
  const mins = Math.max(0, Math.floor((diffMs%3600000)/60000));
  const deliveryDate = new Date(now); deliveryDate.setDate(deliveryDate.getDate() + (pastCutoff ? 6 : 5));
  const dateStr = deliveryDate.toLocaleDateString('en-IN',{day:'2-digit',month:'short'});
  return { hrs, mins, dateStr };
}
