function saveAddress() {
  const name = document.getElementById('addrName').value.trim();
  const phone = document.getElementById('addrPhone').value.trim();
  const pincode = document.getElementById('addrPincode').value.trim();
  const line = document.getElementById('addrLine').value.trim();
  const state = document.getElementById('addrState').value.trim();
  const district = document.getElementById('addrDistrict').value.trim();
  const city = document.getElementById('addrCity').value.trim();
  if(!name || !phone || !pincode || !line || !state || !district || !city) {
    showToast('Please fill in all address fields');
    return;
  }
  if(!currentUser.addresses) currentUser.addresses = [];
  currentUser.addresses.push({name,phone,pincode,line,city,district,state});
  selectedAddressIndex = currentUser.addresses.length - 1;
  toggleAddrForm();
  renderAddressList();
  saveCurrentUserToFirestore();
  showToast('Address saved');
}
async function saveCurrentUserToFirestore() {
  if (!currentUser || !currentUser.uid) return;
  const { db, ref, set } = window.fb;
  try {
    await set(ref(db, 'users/' + currentUser.uid), {
      name: currentUser.name,
      email: currentUser.email,
      phone: currentUser.phone || '',
      joined: currentUser.joined || '',
      orders: currentUser.orders || 0,
      addresses: currentUser.addresses || [],
      isAdmin: !!currentUser.isAdmin,
      lastUpdated: new Date().toISOString()
    });
  } catch(e) { console.error('saveCurrentUserToFirestore failed', e); }
}
function selectPayment(method) {
  selectedPaymentMethod = method;
  document.querySelectorAll('.pay-option').forEach(el=>el.classList.remove('selected'));
  document.querySelectorAll('.pay-fields').forEach(el=>el.classList.remove('show'));
  document.getElementById('payOpt-'+method).classList.add('selected');
  document.getElementById('payRadio-'+method).checked = true;
  const fields = document.getElementById('payFields-'+method);
  if(fields) fields.classList.add('show');
  renderCheckoutSummary();
}
function calcCodCharges(subtotal) {
  const handling = (selectedPaymentMethod === 'cod' && codSettings.handlingEnabled) ? codSettings.handlingFee : 0;
  const gst = (selectedPaymentMethod === 'cod' && codSettings.gstEnabled) ? Math.round(subtotal * codSettings.gstPercent / 100) : 0;
  return { handling, gst, total: subtotal + handling + gst };
}
function renderCheckoutSummary() {
  const list = document.getElementById('checkoutItemsList');
  list.innerHTML = cart.map(i=>`
    <div class="summary-item"><span>${i.name}${i.size?` (${i.size}/${i.color})`:''} x${i.qty}</span><span>₹${(i.price*i.qty).toLocaleString()}</span></div>`).join('');
  const subtotal = cart.reduce((s,i)=>s+(i.price*i.qty),0);
  const { handling, gst } = calcCodCharges(subtotal);
  let couponDiscount = 0;
  if(appliedCoupon) {
    if(appliedCoupon.type === 'percent') couponDiscount = Math.round(subtotal * appliedCoupon.discount / 100);
    else couponDiscount = Math.min(appliedCoupon.discount, subtotal);
  }
  const afterDiscount = subtotal - couponDiscount;
  const total = afterDiscount + handling + gst;
  let codHTML = '';
  if (selectedPaymentMethod === 'cod') {
    codHTML = `<div id="codChargesBox" style="border-top:1px solid var(--border);margin:0.8rem 0;padding-top:0.8rem">
      <div style="font-size:0.65rem;letter-spacing:0.2em;text-transform:uppercase;color:var(--gold);margin-bottom:0.6rem">Cash on Delivery Charges</div>
      <div class="summary-item" style="color:var(--gray)"><span>Subtotal</span><span>₹${subtotal.toLocaleString()}</span></div>
      ${couponDiscount>0 ? `<div class="summary-item" style="color:#5aaa6a"><span>Coupon (${escHTML(appliedCoupon.code)})</span><span>− ₹${couponDiscount.toLocaleString()}</span></div>` : ''}
      ${codSettings.handlingEnabled ? `<div class="summary-item" style="color:var(--gray)"><span>COD Handling Fee</span><span>+ ₹${handling}</span></div>` : ''}
      ${codSettings.gstEnabled ? `<div class="summary-item" style="color:var(--gray)"><span>GST (${codSettings.gstPercent}%)</span><span>+ ₹${gst.toLocaleString()}</span></div>` : ''}
    </div>`;
  } else if(couponDiscount > 0) {
    codHTML = `<div id="codChargesBox" style="border-top:1px solid var(--border);margin:0.8rem 0;padding-top:0.8rem">
      <div class="summary-item" style="color:var(--gray)"><span>Subtotal</span><span>₹${subtotal.toLocaleString()}</span></div>
      <div class="summary-item" style="color:#5aaa6a"><span>Coupon (${escHTML(appliedCoupon.code)})</span><span>− ₹${couponDiscount.toLocaleString()}</span></div>
    </div>`;
  } else {
    codHTML = `<div id="codChargesBox"></div>`;
  }
  const existing = document.getElementById('codChargesBox');
  if (existing) {
    existing.outerHTML = codHTML || `<div id="codChargesBox"></div>`;
  } else {
    list.insertAdjacentHTML('afterend', codHTML || `<div id="codChargesBox"></div>`);
  }
  document.getElementById('checkoutTotal').textContent = '₹'+total.toLocaleString();
}
function placeOrder() {
  const err = document.getElementById('checkoutError');
  if(selectedAddressIndex===null || !currentUser.addresses || !currentUser.addresses[selectedAddressIndex]) {
    err.textContent = 'Please select or add a delivery address.';
    err.style.display = 'block';
    return;
  }
  if(!selectedPaymentMethod) {
    err.textContent = 'Please select a payment method.';
    err.style.display = 'block';
    return;
  }
  if(selectedPaymentMethod==='upi' && !document.getElementById('upiId').value.trim()) {
    err.textContent = 'Please enter your UPI ID.';
    err.style.display = 'block';
    return;
  }
  if(selectedPaymentMethod==='card') {
    const num = document.getElementById('cardNumber').value.trim();
    const exp = document.getElementById('cardExpiry').value.trim();
    const cvv = document.getElementById('cardCvv').value.trim();
    if(!num || !exp || !cvv) {
      err.textContent = 'Please fill in all card details.';
      err.style.display = 'block';
      return;
    }
  }
  err.style.display = 'none';
  const addr = currentUser.addresses[selectedAddressIndex];
  const paymentLabels = {upi:'UPI', card:'Card', cod:'Cash on Delivery'};
  const subtotal = cart.reduce((s,i)=>s+(i.price*i.qty),0);
  const { handling, gst } = calcCodCharges(subtotal);
  let couponDiscount = 0;
  if(appliedCoupon) {
    if(appliedCoupon.type === 'percent') couponDiscount = Math.round(subtotal * appliedCoupon.discount / 100);
    else couponDiscount = Math.min(appliedCoupon.discount, subtotal);
  }
  const total = subtotal - couponDiscount + handling + gst;
  const orderId = 'SH-'+String(orders.length+1001);
  const order = {
    id: orderId,
    uid: currentUser.uid,
    customer: currentUser.name,
    email: currentUser.email,
    phone: currentUser.phone || '',
    items: cart.map(i=>`${i.name}${i.size?` (${i.size}/${i.color})`:''} x${i.qty}`).join(', '),
    itemDetails: cart.map(i=>({
      id: i.id,
      name: i.name,
      price: i.price,
      qty: i.qty,
      size: i.size || '',
      color: i.color || '',
      emoji: i.emoji || '',
      image: i.image || ''
    })),
    itemCount: cart.reduce((s,i)=>s+i.qty,0),
    subtotal: subtotal,
    couponCode: appliedCoupon ? appliedCoupon.code : '',
    couponDiscount: couponDiscount,
    codHandling: handling,
    codGst: gst,
    amount: total,
    date: new Date().toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'}),
    status: 'pending',
    address: `${addr.name}, ${addr.phone}, ${addr.line}, ${addr.city}, ${addr.district}, ${addr.state} - ${addr.pincode}`,
    payment: paymentLabels[selectedPaymentMethod]
  };
  currentUser.orders = (currentUser.orders||0)+1;
  cart.forEach(item=>{
    if(item.size) {
      const p = products.find(x=>x.id===item.id);
      const v = p && p.variants && p.variants.find(x=>x.size===item.size && x.color===item.color);
      if(v) v.qty = Math.max(0, v.qty - item.qty);
    }
  });
  const { db, ref, set } = window.fb;
  Promise.all([
    set(ref(db, 'orders/' + orderId), order),
    saveCurrentUserToFirestore(),
    ...cart.filter(i=>i.size).map(item => {
      const p = products.find(x=>x.id===item.id);
      return p ? saveProductToFirestore(p) : Promise.resolve();
    })
  ]).catch((e)=>{
    showFirebaseError('saving order '+orderId, e);
  });
  cart = [];
  appliedCoupon = null;
  updateCartCount();
  saveData();
  renderFeatured();
  renderCollection();
  showPage('profile');
  showToast('✓ Order placed! ID: '+order.id);
}
function withTimeout(promise, ms, label) {
  return Promise.race([
    promise,
    new Promise((_, reject) => setTimeout(() => reject(new Error((label||'Request')+' timed out after '+(ms/1000)+'s — internet connection slow hai, dobara try karein.')), ms))
  ]);
}
function handleUserBtn() {
  if(currentUser) {
    if(currentUser.isAdmin) { showPage('admin'); return; }
    showPage('profile');
  } else {
    showPage('login');
  }
}
function doLogin() {
  const email = document.getElementById('loginEmail').value.trim();
  const pass = document.getElementById('loginPass').value;
  const err = document.getElementById('loginError');
  const btn = document.getElementById('loginBtn');
  err.style.display='none';
  const forgotMsg = document.getElementById('forgotMsg');
  if(forgotMsg) forgotMsg.style.display='none';
  if(!email || !pass) {
    err.textContent = 'Email aur password dono bharo.';
    err.style.display = 'block';
    return;
  }
  if(btn) { btn.disabled = true; btn.textContent = 'Logging in...'; btn.classList.remove('added'); }
  let success = false;
  const { auth, signInWithEmailAndPassword } = window.fb;
  withTimeout(signInWithEmailAndPassword(auth, email, pass), 30000, 'Login')
    .then(() => {
      success = true;
      if(btn) { btn.textContent = '✓ Signed In'; btn.classList.add('added'); }
      if (email === ADMIN_EMAIL) {
        pendingAuthRedirect = 'admin';
      } else {
        pendingAuthRedirect = 'profile';
      }
    })
    .catch((e) => {
      err.textContent = friendlyAuthError(e);
      err.style.display = 'block';
    })
    .finally(() => {
      if(btn) { btn.disabled = false; if(!success) btn.textContent = 'SIGN IN'; }
    });
}
function doForgotPassword() {
  const email = document.getElementById('loginEmail').value.trim();
  const err = document.getElementById('loginError');
  const forgotMsg = document.getElementById('forgotMsg');
  err.style.display = 'none';
  if(!email) {
    err.textContent = 'Pehle apna email address daalo, phir "Forgot Password" dabao.';
    err.style.display = 'block';
    return;
  }
  const { auth, sendPasswordResetEmail } = window.fb;
  const actionCodeSettings = {
    url: window.location.href,
    handleCodeInApp: false
  };
  withTimeout(sendPasswordResetEmail(auth, email, actionCodeSettings), 30000, 'Password reset')
    .then(() => {
      if(forgotMsg) {
        forgotMsg.textContent = '✓ Password reset link "' + email + '" pe bhej diya gaya hai. Please apna inbox check karein (Spam folder bhi dekh lein).';
        forgotMsg.style.display = 'block';
      }
      showToast('Reset link aapke email pe bhej diya gaya hai');
    })
    .catch((e) => {
      let msg = friendlyAuthError(e);
      if(e && e.code === 'auth/user-not-found') msg = 'Is email se koi account nahi mila.';
      err.textContent = msg;
      err.style.display = 'block';
    });
}
function doRegister() {
  const name = document.getElementById('regName').value.trim();
  const email = document.getElementById('regEmail').value.trim();
  const pass = document.getElementById('regPass').value;
  const phone = document.getElementById('regPhone').value.trim();
  const err = document.getElementById('regError');
  const btn = document.getElementById('registerBtn');
  err.style.display='none';
  if(!name||!email||!pass) { err.textContent='Naam, email aur password zaroori hai.'; err.style.display='block'; return; }
  if(pass.length < 6) { err.textContent='Password kam se kam 6 characters ka hona chahiye.'; err.style.display='block'; return; }
  if(btn) { btn.disabled = true; btn.textContent = 'Creating account...'; btn.classList.remove('added'); }
  let success = false;
  const { auth, createUserWithEmailAndPassword, updateProfile, db, ref, set } = window.fb;
  withTimeout(createUserWithEmailAndPassword(auth, email, pass), 30000, 'Signup')
    .then(async (cred) => {
      const profile = {
        name, email, phone,
        joined: new Date().toLocaleDateString('en-US',{month:'short',year:'numeric'}),
        orders: 0, addresses: [],
        isAdmin: email === ADMIN_EMAIL
      };
      try {
        await updateProfile(cred.user, { displayName: name });
      } catch(profileErr) {
        console.error('updateProfile failed', profileErr);
      }
      try {
        await withTimeout(set(ref(db, 'users/' + cred.user.uid), profile), 30000, 'Profile save');
      } catch(dbErr) {
        console.error('Profile save failed', dbErr);
        currentUser = { uid: cred.user.uid, ...profile };
        applySession();
        success = true;
        if(btn) { btn.textContent = '✓ Account Created'; btn.classList.add('added'); }
        showToast('Account ban gaya! Welcome, '+name+'!');
        pendingAuthRedirect = 'profile';
        return;
      }
      currentUser = { uid: cred.user.uid, ...profile };
      applySession();
      success = true;
      if(btn) { btn.textContent = '✓ Account Created'; btn.classList.add('added'); }
      showToast('Account ban gaya! Welcome, '+name+'!');
      pendingAuthRedirect = 'profile';
    })
    .catch((e) => {
      err.textContent = friendlyAuthError(e);
      err.style.display = 'block';
    })
    .finally(() => {
      if(btn) { btn.disabled = false; if(!success) btn.textContent = 'CREATE ACCOUNT'; }
    });
}
function friendlyAuthError(e) {
  const code = e && e.code || '';
  const msg = e && e.message || '';
  if (code.includes('email-already-in-use')) return 'Yeh email pehle se registered hai.';
  if (code.includes('invalid-email')) return 'Valid email address enter karo.';
  if (code.includes('weak-password')) return 'Password kam se kam 6 characters ka hona chahiye.';
  if (code.includes('user-not-found') || code.includes('wrong-password') || code.includes('invalid-credential')) return 'Email ya password galat hai.';
  if (code.includes('network-request-failed') || msg.includes('timed out')) return 'Network error — internet connection check karo aur dobara try karo.';
  if (code.includes('too-many-requests')) return 'Bahut zyada attempts — thodi der baad dobara try karo.';
  if (code.includes('user-disabled')) return 'Yeh account disable kar diya gaya hai.';
  return 'Kuch galat ho gaya: ' + (msg || 'dobara try karo.');
}
