function openVariantManager(productId) {
  variantManagerProductId = productId;
  const p = products.find(x=>x.id===productId);
  if(!p) return;
  if(!p.variants) p.variants = [];
  document.getElementById('variantModalTitle').textContent = 'MANAGE STOCK — '+p.name.toUpperCase();
  renderVariantTable();
  document.getElementById('variantOverlay').classList.add('open');
  document.getElementById('variantModal').classList.add('open');
}
function closeVariantManager() {
  document.getElementById('variantOverlay').classList.remove('open');
  document.getElementById('variantModal').classList.remove('open');
  variantManagerProductId = null;
}
function renderVariantTable() {
  const p = products.find(x=>x.id===variantManagerProductId);
  if(!p) return;
  const tbody = document.getElementById('variantTableBody');
  tbody.innerHTML = p.variants.length ? p.variants.map((v,i)=>`
    <tr>
      <td style="color:var(--white)">${v.size}</td>
      <td>${v.color}</td>
      <td><input type="number" class="variant-qty-input" value="${v.qty}" min="0" onchange="updateVariantQty(${i},this.value)"/></td>
      <td><button class="btn-sm" onclick="deleteVariant(${i})">✕</button></td>
    </tr>`).join('') : '<tr><td colspan="4" style="text-align:center;padding:1.5rem;color:var(--gray)">No size/color variants yet. Add one below.</td></tr>';
}
function addVariantRow() {
  const size = document.getElementById('newVariantSize').value.trim();
  const color = document.getElementById('newVariantColor').value.trim();
  const qty = parseInt(document.getElementById('newVariantQty').value);
  if(!size || !color || isNaN(qty) || qty<0) { showToast('Please enter size, color and a valid quantity'); return; }
  const p = products.find(x=>x.id===variantManagerProductId);
  if(!p) return;
  const existing = p.variants.find(v=>v.size.toLowerCase()===size.toLowerCase() && v.color.toLowerCase()===color.toLowerCase());
  if(existing) existing.qty += qty;
  else p.variants.push({size,color,qty});
  ['newVariantSize','newVariantColor','newVariantQty'].forEach(id=>document.getElementById(id).value='');
  saveData();
  saveProductToFirestore(p).catch((e)=>{ showFirebaseError('saving variant for '+p.id, e); });
  renderVariantTable();
  refreshAdmin();
  renderFeatured();
  renderCollection();
  showToast('Variant saved');
}
function updateVariantQty(index, value) {
  const p = products.find(x=>x.id===variantManagerProductId);
  if(!p) return;
  const qty = parseInt(value);
  p.variants[index].qty = isNaN(qty)||qty<0 ? 0 : qty;
  saveData();
  saveProductToFirestore(p).catch((e)=>{ showFirebaseError('saving variant qty for '+p.id, e); });
  refreshAdmin();
  renderFeatured();
  renderCollection();
}
function deleteVariant(index) {
  const p = products.find(x=>x.id===variantManagerProductId);
  if(!p) return;
  p.variants.splice(index,1);
  saveData();
  saveProductToFirestore(p).catch((e)=>{ showFirebaseError('saving variant delete for '+p.id, e); });
  renderVariantTable();
  refreshAdmin();
  renderFeatured();
  renderCollection();
}
function confirmOrder(orderId) {
  const o = orders.find(x=>x.id===orderId);
  if(o) {
    o.status='processing';
    const { db, ref, update } = window.fb;
    update(ref(db, 'orders/' + (o._docId || orderId)), { status: 'processing' }).catch((e)=>{
      console.error('Order status update failed:', e);
      showToast('⚠ Status database mein update nahi hua: '+(e&&e.code||e&&e.message||'unknown error'));
    });
    showToast('Order '+orderId+' confirmed ✓');
    refreshAdmin();
  }
}
