let _npv = [];
function addNPV() {
  const s = document.getElementById('npvSize').value.trim();
  const c = document.getElementById('npvColor').value.trim();
  const q = parseInt(document.getElementById('npvQty').value);
  const msg = document.getElementById('npvMsg');
  if(!s||!c||isNaN(q)||q<0){msg.textContent='⚠ Size, color aur qty sahi bharo!';msg.style.color='var(--red)';return;}
  const ex = _npv.find(v=>v.size.toLowerCase()===s.toLowerCase()&&v.color.toLowerCase()===c.toLowerCase());
  if(ex) ex.qty+=q; else _npv.push({size:s,color:c,qty:q});
  document.getElementById('npvSize').value='';
  document.getElementById('npvColor').value='';
  document.getElementById('npvQty').value='';
  renderNPV();
}
function removeNPV(i){_npv.splice(i,1);renderNPV();}
function renderNPV(){
  const el=document.getElementById('newPVList');
  const msg=document.getElementById('npvMsg');
  if(!_npv.length){el.innerHTML='';msg.textContent='Add at least one size/color variant before saving.';msg.style.color='var(--gray)';return;}
  el.innerHTML='<div style="background:var(--black);border:1px solid var(--border);margin-bottom:0.5rem">'+
    _npv.map((v,i)=>`<div style="display:flex;align-items:center;gap:0.8rem;padding:0.5rem 0.8rem;border-bottom:1px solid var(--border)">
      <span style="color:var(--white);font-weight:600;font-size:0.82rem">${v.size}</span>
      <span style="color:var(--gray);font-size:0.82rem">${v.color}</span>
      <span style="color:#5aaa6a;font-size:0.82rem;margin-left:auto">Qty: ${v.qty}</span>
      <button class="btn-sm" onclick="removeNPV(${i})" style="border-color:var(--red);color:var(--red)">✕</button>
    </div>`).join('')+'</div>';
  msg.textContent='✓ '+_npv.length+' variant(s) added.';
  msg.style.color='#5aaa6a';
}
function addProduct() {
  const name=document.getElementById('pName').value.trim();
  const cat=document.getElementById('pCat').value;
  const price=parseInt(document.getElementById('pPrice').value);
  const oldPrice=parseInt(document.getElementById('pOldPrice').value)||null;
  const badge=document.getElementById('pBadge').value.trim()||null;
  const emoji=document.getElementById('pEmoji').value.trim()||'👕';
  const desc=document.getElementById('pDesc').value.trim();
  if(!name||!price){showToast('⚠ Naam aur price zaroori hai!');return;}
  if(!_npv.length){showToast('⚠ Kam se kam ek size/color add karo!');return;}
  const newProduct = {id:nextId++,name,cat,price,oldPrice,badge,emoji,desc,images:[],variants:[..._npv]};
  products.push(newProduct);
  _npv=[];
  ['pName','pPrice','pOldPrice','pBadge','pEmoji','pDesc'].forEach(id=>document.getElementById(id).value='');
  document.getElementById('newPVList').innerHTML='';
  document.getElementById('npvMsg').textContent='Add at least one size/color variant before saving.';
  document.getElementById('npvMsg').style.color='var(--gray)';
  saveProductToFirestore(newProduct)
    .then(() => { showToast('✓ Product add ho gaya: '+name); })
    .catch((e) => { showFirebaseError('adding product '+name, e); });
  refreshAdmin();
  renderFeatured();
  renderCollection();
}
function toggleSP(pid){var el=document.getElementById('sp-'+pid);if(el)el.style.display=el.style.display==='none'?'block':'none';}
function toggleEditPanel(pid){var el=document.getElementById('ep-'+pid);if(el)el.style.display=el.style.display==='none'?'block':'none';}
function adminImgGridHTML(p){
  var imgs = p.images || [];
  var html = imgs.map(function(src,i){
    return '<div class="admin-img-thumb"><img src="'+src+'"/><button class="admin-img-del" onclick="removeProductImage('+p.id+','+i+')">✕</button></div>';
  }).join('');
  html += '<label class="admin-img-upload-btn">+<input type="file" accept="image/*" multiple style="display:none" onchange="uploadProductImages('+p.id+',this.files)"/></label>';
  return html;
}
function uploadProductImages(pid, files){
  var p = products.find(function(x){return x.id===pid;});
  if(!p || !files || !files.length) return;
  if(!p.images) p.images=[];
  var remaining = files.length;
  Array.prototype.forEach.call(files, function(file){
    var reader = new FileReader();
    reader.onload = function(e){
      p.images.push(e.target.result);
      remaining--;
      if(remaining===0){
        saveData();
        saveProductToFirestore(p).catch((e)=>{ showFirebaseError('saving images for '+p.id, e); });
        var grid = document.getElementById('img-grid-'+pid);
        if(grid) grid.innerHTML = adminImgGridHTML(p);
        renderFeatured();
        renderCollection();
        if(currentPDProductId===pid) renderProductDetail();
        showToast('✓ Image(s) uploaded');
      }
    };
    reader.readAsDataURL(file);
  });
}
function removeProductImage(pid, idx){
  var p = products.find(function(x){return x.id===pid;});
  if(!p || !p.images) return;
  p.images.splice(idx,1);
  saveData();
  saveProductToFirestore(p).catch((e)=>{ showFirebaseError('saving image removal for '+p.id, e); });
  var grid = document.getElementById('img-grid-'+pid);
  if(grid) grid.innerHTML = adminImgGridHTML(p);
  renderFeatured();
  renderCollection();
  if(currentPDProductId===pid) renderProductDetail();
}
function saveProductEdit(pid){
  var p = products.find(function(x){return x.id===pid;});
  if(!p) return;
  var name = document.getElementById('ep-name-'+pid).value.trim();
  var cat = document.getElementById('ep-cat-'+pid).value;
  var badge = document.getElementById('ep-badge-'+pid).value.trim();
  var price = parseInt(document.getElementById('ep-price-'+pid).value);
  var oldPrice = parseInt(document.getElementById('ep-oldprice-'+pid).value);
  var desc = document.getElementById('ep-desc-'+pid).value.trim();
  if(!name || isNaN(price)){ showToast('⚠ Naam aur price zaroori hai!'); return; }
  p.name = name;
  p.cat = cat;
  p.badge = badge || null;
  p.price = price;
  p.oldPrice = isNaN(oldPrice) ? null : oldPrice;
  p.desc = desc;
  saveData();
  saveProductToFirestore(p).catch((e)=>{ showFirebaseError('saving product edit for '+p.id, e); });
  showToast('✓ Product details updated: '+name);
  refreshAdmin();
  renderFeatured();
  renderCollection();
  if(currentPDProductId===pid) renderProductDetail();
}
function spQty(pid,idx,d){var p=products.find(function(x){return x.id===pid;});if(!p||!p.variants[idx])return;p.variants[idx].qty=Math.max(0,p.variants[idx].qty+d);saveData();saveProductToFirestore(p).catch(function(e){showFirebaseError('saving stock for '+p.id, e);});refreshAdmin();renderFeatured();renderCollection();var el=document.getElementById('sp-'+pid);if(el)el.style.display='block';}
function spQtySet(pid,idx,val){var p=products.find(function(x){return x.id===pid;});if(!p||!p.variants[idx])return;var q=parseInt(val);p.variants[idx].qty=isNaN(q)||q<0?0:q;saveData();saveProductToFirestore(p).catch(function(e){showFirebaseError('saving stock for '+p.id, e);});renderFeatured();renderCollection();}
function spDelV(pid,idx){var p=products.find(function(x){return x.id===pid;});if(!p)return;p.variants.splice(idx,1);saveData();saveProductToFirestore(p).catch(function(e){showFirebaseError('saving variant delete for '+p.id, e);});refreshAdmin();renderFeatured();renderCollection();var el=document.getElementById('sp-'+pid);if(el)el.style.display='block';}
function spAddV(pid){var s=(document.getElementById('ss-'+pid)||{}).value.trim();var c=(document.getElementById('sc-'+pid)||{}).value.trim();var q=parseInt((document.getElementById('sq-'+pid)||{}).value);if(!s||!c||isNaN(q)||q<0){showToast('Size, color aur qty sahi bharo!');return;}var p=products.find(function(x){return x.id===pid;});if(!p)return;if(!p.variants)p.variants=[];var ex=p.variants.find(function(v){return v.size.toLowerCase()===s.toLowerCase()&&v.color.toLowerCase()===c.toLowerCase();});if(ex)ex.qty+=q;else p.variants.push({size:s,color:c,qty:q});saveData();saveProductToFirestore(p).catch(function(e){showFirebaseError('saving variant for '+p.id, e);});showToast('Variant add ho gaya!');refreshAdmin();renderFeatured();renderCollection();var el=document.getElementById('sp-'+pid);if(el)el.style.display='block';}
function deleteProduct(id) {
  if(!confirm('Delete this product?')) return;
  const target = products.find(p=>p.id===id);
  products = products.filter(p=>p.id!==id);
  if (target) deleteProductFromFirestore(target).catch((e)=>{
    console.error('Delete product Firestore sync failed:', e);
    showToast('⚠ Product Firestore se delete nahi hua: '+(e&&e.code||e&&e.message||'unknown error'));
  });
  showToast('Product deleted');
  refreshAdmin();
  renderFeatured();
}
function updateOrderStatus(orderId, status) {
  const o = orders.find(x=>x.id===orderId);
  if(o) {
    o.status=status;
    const { db, ref, update } = window.fb;
    update(ref(db, 'orders/' + (o._docId || orderId)), { status }).catch((e)=>{
      console.error('Order status update failed:', e);
      showToast('⚠ Status database mein update nahi hua: '+(e&&e.code||e&&e.message||'unknown error'));
    });
    showToast('Order '+orderId+' → '+status);
    refreshAdmin();
  }
}
function initFirebaseAuthListener() {
  const { auth, onAuthStateChanged, db, ref, get, set, update } = window.fb;
  onAuthStateChanged(auth, async (fbUser) => {
    if (!fbUser) {
      currentUser = null;
      stopUsersSync();
      const btn = document.getElementById('userBtn');
      if (btn) btn.textContent = 'Login';
      renderHomeGallery();
      return;
    }
    try {
      const snap = await withTimeout(get(ref(db, 'users/' + fbUser.uid)), 30000, 'Profile load');
      let profile;
      if (snap.exists()) {
        profile = snap.val();
        if (fbUser.email === ADMIN_EMAIL && !profile.isAdmin) {
          profile.isAdmin = true;
          await update(ref(db, 'users/' + fbUser.uid), { isAdmin: true });
        }
      } else {
        profile = {
          name: fbUser.displayName || (fbUser.email === ADMIN_EMAIL ? 'Admin' : fbUser.email.split('@')[0]),
          email: fbUser.email, phone: fbUser.phoneNumber || '',
          joined: new Date().toLocaleDateString('en-US',{month:'short',year:'numeric'}),
          orders: 0, addresses: [], isAdmin: fbUser.email === ADMIN_EMAIL
        };
        await set(ref(db, 'users/' + fbUser.uid), profile);
      }
      currentUser = { uid: fbUser.uid, ...profile };
      applySession();
      if (currentUser.isAdmin) startUsersSync(); else stopUsersSync();
      if (pendingAuthRedirect) {
        showToast(currentUser.isAdmin ? 'Welcome, Admin!' : 'Welcome back, '+currentUser.name.split(' ')[0]+'!');
        showPage(pendingAuthRedirect);
        pendingAuthRedirect = null;
      }
    } catch(e) {
      showFirebaseError('loading profile after login', e);
      currentUser = {
        uid: fbUser.uid,
        name: fbUser.displayName || fbUser.email.split('@')[0],
        email: fbUser.email,
        phone: '', joined: '', orders: 0, addresses: [],
        isAdmin: fbUser.email === ADMIN_EMAIL
      };
      applySession();
      if (pendingAuthRedirect) {
        showPage(pendingAuthRedirect);
        pendingAuthRedirect = null;
      }
      showToast('⚠ Profile sync nahi ho payi, lekin login ho gaya.');
    }
  });
}
function bootApp() {
  loadData();           
  updateWishCount();    
  initFirebaseAuthListener();
  startProductsSync();
  startOrdersSync();
  startCodSettingsSync();
  startCouponsSync();
  startHomeGallerySync();
  loadHomeSections();
  startCollectionsSync();
  seedProductsIfEmpty().catch((e)=>{ showFirebaseError('seeding starter products', e); });
  seedCouponsIfEmpty().catch((e)=>{ console.warn('Coupon seed skipped:', e && e.code); });
  updateCartCount();
}
async function seedCouponsIfEmpty() {
  const { db, ref, get, set } = window.fb;
  const snap = await get(ref(db, 'coupons'));
  if (snap.exists()) return;
  const defaultCoupons = [
    { code: 'WELCOME10', type: 'percent', discount: 10, minOrder: 0, maxUses: 0, active: true, usedCount: 0, createdAt: Date.now() },
    { code: 'SAVE200', type: 'flat', discount: 200, minOrder: 1000, maxUses: 0, active: true, usedCount: 0, createdAt: Date.now() },
    { code: 'STYLE15', type: 'percent', discount: 15, minOrder: 2000, maxUses: 100, active: true, usedCount: 0, createdAt: Date.now() },
  ];
  for (const c of defaultCoupons) {
    await set(ref(db, 'coupons/' + c.code), c);
  }
}
if (window.fb) {
  bootApp();
} else {
  window.addEventListener('firebase-ready', bootApp, { once: true });
}
